use bitcoin::{check_pow_chain, count_leading_zero_bits};
use common::bytes_32_to_field_pair;
use poseidon::poseidon2;

global MAX_CHAIN_LEN: u32 = 2;
global MIN_ALLTIME_DIFF: u32 = 9;

fn main(
    n_blocks: Field,
    zero_block: [u8; 32],
    time_headers: [[u8; 80]; MAX_CHAIN_LEN],
    poseidon_hash: pub Field,
) {
    let start_difficulty = count_leading_zero_bits(zero_block);
    assert(MIN_ALLTIME_DIFF <= start_difficulty, "Assertion failed at minimal allowed difficulty");

    let (low, high) = bytes_32_to_field_pair(zero_block);

    let zero_block_hash = poseidon2::Poseidon2::hash([low, high], 2);
    let timechain_commitment = poseidon2::Poseidon2::hash([zero_block_hash, n_blocks], 2);
    assert(timechain_commitment == poseidon_hash);

    assert(check_pow_chain(time_headers, zero_block, n_blocks));
}

// =====================================================================
// Test fixtures
// =====================================================================
//
// Anchor: block 946920 -- hash (BE display)
//     00000000000000000000e77cb61854a79b95637fee9dba27ba17ac1ded7ca1f8
// Headers below are the 80-byte serialized headers for heights
// 946921..946926, fetched from mempool.space. Each header's prev_block_hash
// links to the previous block, so all six chain back to the anchor.

fn anchor_zero_block() -> [u8; 32] {
    [
        0xf8, 0xa1, 0x7c, 0xed, 0x1d, 0xac, 0x17, 0xba, 0x27, 0xba, 0x9d, 0xee, 0x7f, 0x63, 0x95,
        0x9b, 0xa7, 0x54, 0x18, 0xb6, 0x7c, 0xe7, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00,
    ]
}

fn header_946921() -> [u8; 80] {
    [
        0x00, 0x40, 0x0b, 0x20, 0xf8, 0xa1, 0x7c, 0xed, 0x1d, 0xac, 0x17, 0xba, 0x27, 0xba, 0x9d,
        0xee, 0x7f, 0x63, 0x95, 0x9b, 0xa7, 0x54, 0x18, 0xb6, 0x7c, 0xe7, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0xee, 0xa2, 0x39, 0xdc, 0xe3, 0x77, 0x3c, 0x5f, 0x61,
        0x79, 0xd2, 0xd1, 0x49, 0xb2, 0x5f, 0x1b, 0x17, 0xf6, 0x49, 0x33, 0x86, 0x95, 0x5c, 0xf5,
        0x3f, 0xc7, 0x04, 0x5a, 0x39, 0xb8, 0xc6, 0x00, 0x0c, 0xc8, 0xef, 0x69, 0x69, 0x13, 0x02,
        0x17, 0xe3, 0x10, 0xa9, 0x35,
    ]
}

fn header_946922() -> [u8; 80] {
    [
        0x00, 0x00, 0x07, 0x20, 0xcf, 0x51, 0x90, 0x4c, 0xcc, 0x0c, 0xf4, 0x7b, 0x6a, 0xab, 0xf0,
        0xcc, 0xfe, 0x55, 0x5c, 0x19, 0x77, 0x7c, 0xf6, 0x62, 0x06, 0x01, 0x02, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x74, 0x3f, 0xc7, 0xf1, 0xaf, 0xc9, 0x8f, 0x0e, 0x2f,
        0x4e, 0x20, 0xc4, 0x0c, 0xb2, 0x11, 0x35, 0x07, 0x8a, 0x30, 0x5c, 0x01, 0xb9, 0x05, 0xe7,
        0xc5, 0x26, 0xac, 0x10, 0xb7, 0xb4, 0x25, 0xc9, 0xf2, 0xc9, 0xef, 0x69, 0x69, 0x13, 0x02,
        0x17, 0x65, 0xdb, 0x8d, 0x21,
    ]
}

fn poseidon_commitment(zero_block: [u8; 32], n_blocks: Field) -> Field {
    let (low, high) = bytes_32_to_field_pair(zero_block);
    let zero_block_hash = poseidon2::Poseidon2::hash([low, high], 2);
    poseidon2::Poseidon2::hash([zero_block_hash, n_blocks], 2)
}

#[test]
fn test_main_two_blocks() {
    let zero_block = anchor_zero_block();

    let mut time_headers: [[u8; 80]; MAX_CHAIN_LEN] = [[0; 80]; MAX_CHAIN_LEN];
    time_headers[0] = header_946921();
    time_headers[1] = header_946922();
    // remaining slots left as zero padding

    let n_blocks = 2 as Field;
    let poseidon_hash = poseidon_commitment(zero_block, n_blocks);
    println(f"poseidon_hash (n=2) = {poseidon_hash}");

    main(n_blocks, zero_block, time_headers, poseidon_hash);
}

/*
fn header_946923() -> [u8; 80] {
    [
